"use client";

import { useState } from "react";
import {
  Button, Input, Label,
  Popover, PopoverContent, PopoverDescription,
  PopoverHeader, PopoverTitle, PopoverTrigger,
} from "@repo/components";

export default function PopoverWithForm() {
  const [open, setOpen] = useState(false);

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button variant="outline">Edit Profile</Button>
      </PopoverTrigger>
      <PopoverContent>
        <PopoverHeader>
          <PopoverTitle>Edit Profile</PopoverTitle>
          <PopoverDescription>Make changes to your profile here.</PopoverDescription>
        </PopoverHeader>
        <div className="grid gap-2">
          <div className="grid gap-1">
            <Label htmlFor="name">Name</Label>
            <Input id="name" defaultValue="John Doe" />
          </div>
          <div className="grid gap-1">
            <Label htmlFor="username">Username</Label>
            <Input id="username" defaultValue="@johndoe" />
          </div>
        </div>
        <div className="flex justify-end">
          <Button size="sm" onClick={() => setOpen(false)}>Save changes</Button>
        </div>
      </PopoverContent>
    </Popover>
  );
}

import {
  Button, Popover, PopoverContent,
  PopoverHeader, PopoverTitle, PopoverDescription, PopoverTrigger,
} from "@repo/components";

export default function PopoverAlignments() {
  return (
    <div className="flex gap-2">
      {["start", "center", "end"].map((align) => (
        <Popover key={align}>
          <PopoverTrigger asChild>
            <Button variant="outline" size="sm" className="capitalize">{align}</Button>
          </PopoverTrigger>
          <PopoverContent align={align}>
            <PopoverHeader>
              <PopoverTitle>Align: {align}</PopoverTitle>
              <PopoverDescription>This popover is aligned to the {align}.</PopoverDescription>
            </PopoverHeader>
          </PopoverContent>
        </Popover>
      ))}
    </div>
  );
}
